import { MainSchema } from "@/db/db.schema";
import { uuid, text, numeric, timestamp, boolean } from "drizzle-orm/pg-core";
import { OrganizationsTable } from "@/features/master-data/organization.model";
import { GrnItemsTable } from "@/features/inbound/grns.model";

/**
 * Delivery Orders Table (Outbound)
 * 
 * @description Document issued by SME upon goods delivery to ES's branch.
 * Each Delivery Order is created from a Transfer Order and represents
 * the actual delivery execution. No partial deliveries, splits, or backorders.
 * 
 * @field doNo - Unique Delivery Order number generated by SME
 * @field toId - Reference to the source Transfer Order (one-to-one)
 * 
 * @status (simplified flow used by advance step)
 * - NEW / CREATED: DO created
 * - PACKING: Items being packed at warehouse
 * - SHIPPED: Goods have left the warehouse (triggers PO status → SHIPPED)
 * - DELIVERED: Delivered at destination
 * Legacy: PICKING, PACKED, READY_FOR_COLLECTION, COLLECTED, DELIVERED_*, CANCELLED
 */
export const DeliveryOrdersTable = MainSchema.table('delivery_orders', {
  id: uuid('id').defaultRandom().notNull().primaryKey(),
  organizationId: uuid('organization_id').notNull().references(() => OrganizationsTable.organizationId),
  doNo: text('delivery_order_no').unique().notNull(),
  purchaseOrderId: uuid('purchase_order_id').unique().notNull(),
  poNo: text('purchase_order_no').notNull(),

  status: text('status').notNull().default('CREATED'),
  isEmergency: boolean('is_emergency').notNull().default(false),

  createdAt: timestamp('created_at', { withTimezone: true }).defaultNow().notNull(),
  updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow().notNull(),
  createdBy: text('created_by').notNull(),
  updatedBy: text('updated_by'),
});

/**
 * Delivery Order Items Table
 * 
 * @description Line items for each Delivery Order.
 * Tracks the required, picked, and packed quantities for each SKU.
 * 
 * @field doId - Reference to the parent Delivery Order
 * @field skuId - Reference to the SKU being delivered
 * @field qtyRequired - Quantity required (from Transfer Order)
 * @field qtyPicked - Quantity actually picked from warehouse
 * @field qtyPacked - Quantity packed for delivery
 */
export const DeliveryOrderItemsTable = MainSchema.table('delivery_order_items', {
  id: uuid('id').defaultRandom().notNull().primaryKey(),
  purchaseOrderId: uuid('purchase_order_id').notNull(),
  purchaseOrderNo: text('purchase_order_no').notNull(),
  skuId: uuid('sku_id').notNull(),
  qtyRequired: numeric('qty_required', { precision: 10, scale: 2 }).notNull(),
  qtyPicked: numeric('qty_picked', { precision: 10, scale: 2 }).default('0'),
  qtyPacked: numeric('qty_packed', { precision: 10, scale: 2 }).default('0'),
  expiryDate: timestamp('expiry_date'),
  lotNo: text('lot_no'),

  createdAt: timestamp('created_at', { withTimezone: true }).defaultNow().notNull(),
  updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow().notNull(),
  createdBy: text('created_by').notNull(),
  updatedBy: text('updated_by'),
});

/**
 * DO Item Allocations Table
 *
 * @description Records which GRN batch (lot) contributes what quantity to each
 * delivery order item. Generated by the pick-list allocation algorithm when
 * a warehouse keeper begins picking (DO status moves to PICKING).
 *
 * Allocation order is determined by the SKU's picking_strategy (FIFO/LIFO/FEFO)
 * plus any priority_flag overrides on individual GRN items.
 */
export const DoItemAllocationsTable = MainSchema.table('do_item_allocations', {
  id: uuid('id').defaultRandom().notNull().primaryKey(),
  doItemId: uuid('do_item_id').notNull().references(() => DeliveryOrderItemsTable.id, { onDelete: 'cascade' }),
  grnItemId: uuid('grn_item_id').notNull().references(() => GrnItemsTable.id, { onDelete: 'cascade' }),
  /** Rack the batch is stored in (optional — null when not rack-tracked). */
  rackId: uuid('rack_id'),
  qtyAllocated: numeric('qty_allocated', { precision: 10, scale: 2 }).notNull(),
  createdAt: timestamp('created_at', { withTimezone: true }).defaultNow().notNull(),
});

export type DoItemAllocationType = typeof DoItemAllocationsTable.$inferSelect;
export type DoItemAllocationInsertType = typeof DoItemAllocationsTable.$inferInsert;

export type DeliveryOrderType = typeof DeliveryOrdersTable.$inferSelect;
export type DeliveryOrderInsertType = typeof DeliveryOrdersTable.$inferInsert;
export type DeliveryOrderFilter = {
  id?: string | string[];
  doNo?: string;
  toId?: string | string[];
  status?: string | string[];
  isEmergency?: boolean;
  createdBy?: string | string[];
  createdAtFrom?: string;
  createdAtTo?: string;
};

export type DeliveryOrderItemType = typeof DeliveryOrderItemsTable.$inferSelect;
export type DeliveryOrderItemInsertType = typeof DeliveryOrderItemsTable.$inferInsert;
export type DeliveryOrderItemFilter = {
  id?: string | string[];
  doId?: string | string[];
  skuId?: string | string[];
  regionId?: string;
  /** When non-empty, outlet region must be one of these (takes precedence over regionId). */
  regionIds?: string[];
  scheduledDeliveryDateFrom?: string;
  scheduledDeliveryDateTo?: string;
};
